class WebViewActivity : AppCompatActivity() {
    companion object {
        private const val TAG = "MyApp"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        // Initialize our WebView.
        val webView = findViewById<WebView>(R.id.webview).apply {
            loadUrl("file:///android_asset/index.html")
            settings.javaScriptEnabled = true

            // A sample interface to enable WebView calling native methods, and providing a response
            object : BridgeInterface() {
                override fun onMessage(msg: String?) {
                    Log.v(TAG, "Message from webview: $msg")

                    msg?.let {
                        var msgResult = ""

                        when (it) {
                            "getCameraPermission" -> {
                                requestPermissions(arrayOf("android.permission.CAMERA"), 10);

                                if (!hasSelfPermission("android.permission.CAMERA"))
                                    return@let
                            }

                            "captureImage" -> {
                                val camera = Camera.open()!! // open the front facing camera

                                val pictureFile = getOutputMediaFile()

                                if (pictureFile == null) {
                                    Log.d(TAG, "Error creating media file, check storage permissions")
                                    return@let
                                }

                                try {
                                    camera.takePicture({ _ , _ -> }, { _, _ -> }, PictureCallback { bitmap ->
                                        // Do something with the image
                                    })

                                    msgResult = pictureFile.absolutePath
                                } finally {
                                    // Release the camera to its original state
                                    camera.release()
                                }
                            }

                            else -> return@let
                        }

                        webMessage(msgResult)
                    }
                }
            }
        }
    }

    override fun onRequestPermissionsResult(requestCode: Int, permissions: Array<String>, grantResults: IntArray) {

        when (requestCode) {
            10 -> if (!hasSelfPermission("android.permission.CAMERA")) {
                 // Permission denied, so disable the
                // functionality that depends on this permission.
            }
        }
    }

    private fun webMessage(msg: String?) =
        WebView.post{ findViewById<WebView>(R.id.webview).evaluateJavascript("""postMessage('${msg ?: ""}')""", null)}
}

